import { Manifest } from '@verdaccio/types'

export type readmeVersion = {
  version: string
  markdown: string
}

export const getReadmesFromManifest = (manifest: Manifest): readmeVersion[] => {
  const readmes: readmeVersion[] = []
  for (const version in manifest.versions) {
    const readme = manifest.versions[version].readme
    if (readme) {
      readmes.push({ version, markdown: readme })
    }
  }
  const latest = manifest.readme
  if (latest) {
    readmes.push({ version: 'latest', markdown: latest })
  }
  return readmes
}

export const clearReadmesFromManifest = (manifest: Manifest): Manifest => {
  const manifestCopy = JSON.parse(JSON.stringify(manifest))
  for (const version in manifestCopy.versions) {
    manifestCopy.versions[version].readdown = ''
  }
  manifestCopy.readme = ''
  return manifestCopy
}

export const mergeReadmesIntoManifest = (manifest: Manifest, readmes: readmeVersion[]): Manifest => {
  const manifestCopy = JSON.parse(JSON.stringify(manifest))
  for (const readme of readmes) {
    if (readme.version === 'latest') {
      manifestCopy.readme = readme.markdown
    }
    else if (manifestCopy.versions[readme.version]) {
      manifestCopy.versions[readme.version].readme = readme.markdown
    }
  }
  return manifestCopy
}

export type metadataVersion = {
  version: string
  description: string
  keywords: string
}

export const getMetadataFromManifest = (manifest: Manifest): metadataVersion[] => {
  const metadata: metadataVersion[] = []
  for (const version in manifest.versions) {
    const packageVersion = manifest.versions[version]
    const description = packageVersion.description || ''
    const keywords = Array.isArray(packageVersion.keywords) ? packageVersion.keywords.join(' ') : packageVersion.keywords || ''
    metadata.push({ version, description, keywords })
  }
  return metadata
}
