import { readFileSync } from 'node:fs'
import { resolve } from 'node:path'
import { drizzle } from 'drizzle-orm/node-postgres'

import { Logger } from '@verdaccio/types'

import { ENV } from '../env'
import { loggerFactory } from './logger'

export type Database = ReturnType<typeof drizzle>

export const getDatabase = (url: string, logger?: Logger): Database => {
  const drizzleLogger = loggerFactory(logger)

  // Configure SSL based on environment variables
  const sslConfig = ENV.DB_SSL
    ? {
        rejectUnauthorized: ENV.DB_SSL_REJECT_UNAUTHORIZED,
        ca: ENV.DB_SSL_CA_PATH
          ? readFileSync(resolve(ENV.DB_SSL_CA_PATH), 'utf8')
          : ENV.DB_SSL_CA ?? undefined,
        cert: ENV.DB_SSL_CERT_PATH
          ? readFileSync(resolve(ENV.DB_SSL_CERT_PATH), 'utf8')
          : ENV.DB_SSL_CERT ?? undefined,
        key: ENV.DB_SSL_KEY_PATH
          ? readFileSync(resolve(ENV.DB_SSL_KEY_PATH), 'utf8')
          : ENV.DB_SSL_KEY ?? undefined,
      }
    : false

  const isSingleConnection
    = ENV.DATABASE_URL.includes('localhost')
      || ENV.DATABASE_URL.includes('127.0.0.1')
      || ENV.DATABASE_URL.includes('file:')
      || ENV.DB_MIGRATING
      || ENV.DB_SEEDING
      || ENV.DB_RESET

  const db = drizzle({
    connection: {
      connectionString: url,
      max: isSingleConnection ? 1 : ENV.DB_POOL_SIZE,
      ssl: sslConfig,
    },
    logger: drizzleLogger,
  })

  return db
}
