export const getScopeFromName = (name: string): string => {
  return name.startsWith('@') ? name.split('/')[0] : ''
}

export const getPackageFromName = (name: string): string => {
  return name.startsWith('@') ? name.split('/')[1] : name
}

export const getNameFromPackageAndScope = (packageName: string, scope: string): string => {
  return scope.length > 0 ? `${scope}/${packageName}` : packageName
}

export const getPackageInfoFromFilename = (filename: string): { name: string, version: string } => {
  const match = filename.match(/^(.*)-(\d+\.\d+\.\d+.*)\.tgz$/)
  if (!match) {
    throw new Error(`Invalid tarball filename: ${filename}`)
  }
  return { name: match[1], version: match[2] }
}

export const getISODate = (date: string): string => {
  return new Date(date).toISOString().split('T')[0]
}

export const getISODates = (start: string, end?: string): string[] => {
  const dates: string[] = []
  dates.push(getISODate(start))
  dates.push(getISODate(end || start))
  return dates
}

export const unescapeHtmlEntities = (json: string): string => {
  return json.replace(/\\u003e/g, '>').replace(/\\u003c/g, '<').replace(/\\u0026/g, '&')
}
